using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with a known type context
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"Roundtrip: {JsonSerializer.Serialize(new Person("Ada", 37), personInfo)}");

// 2) Probe without throwing: TryGetTypeInfo returns false instead of an exception
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"\nTryGetTypeInfo(Person)  -> found={found}, type={info?.Type.Name}");

// Use a resolver that only knows about Person, so Widget is unknown
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new SpecificContext())   // only exposes Person
};

bool foundWidget = limited.TryGetTypeInfo(typeof(Widget), out JsonTypeInfo? widgetInfo);
Console.WriteLine($"TryGetTypeInfo(Widget) -> found={foundWidget}, info is null={widgetInfo is null}");

// ------- types -------
record Person(string Name, int Age);
record Widget(int Id);

// A custom context that deliberately only resolves Person
[JsonSerializable(typeof(Person))]
partial class SpecificContext : JsonSerializerContext;

